-- Enrichment marathon batch: Bebo, Bedrock Analytics, Beezwax Datatools, Befonts, Benchmark, Benevity, Better Stack (Better Uptime), Betterbird

-- ── Bebo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bebo is a free social app relaunched by its original founders around small, private group chats called Crews, replacing public feeds and like counts with real-time conversation.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Small, founder-led team$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bebo in 2026: What The Relaunched Social App Does Now$q$, seo_title),
  seo_meta_description = COALESCE($q$Bebo is back, run by its founders as a free group chat app built around private Crews. See what Bebo does today and how it works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bebo is a free social networking and group chat app currently owned and operated by its original founders, Michael and Xochi Birch, who first launched Bebo in January 2005 from their home in San Francisco. The original Bebo grew into one of the largest social networks of the mid-2000s, competing with MySpace and Facebook, and was acquired by AOL in March 2008 for approximately 850 million US dollars. AOL sold the struggling network to Criterion Capital Partners in 2010, and the Birches bought Bebo back for around 1 million US dollars in 2013. Since regaining control, the founders have relaunched Bebo multiple times under different concepts, including a 2014 video walkie-talkie app called Blab, and a mobile social and livestreaming app released around 2017 that was shut down by roughly 2019-2020 after failing to gain traction; a subsequent private-beta attempt was also discontinued by 2022. The current version of Bebo, actively developed and re-released in stages through the mid-2020s, abandons the newsfeed, follower counts, and like buttons that defined both the original Bebo and most modern social platforms. Instead, the product is organized around Crews, private group chats of up to roughly 100 people intended for close friend groups rather than broad public audiences. A companion feature called the Spectator Model lets a Crew opt into a semi-public mode, similar to a live, readable podcast, where a core group of up to 50 participants chats while outside spectators can watch without joining the conversation. Bebo is free for individual members, with no subscription fee required to create or join a Crew. Because Bebo has cycled through so many relaunches and shutdowns since 2013, its current user base and market traction are modest compared with the original 2005-2013 network, and the product should be understood as an independent, founder-funded project rather than a mainstream social platform. Gappsy lists Bebo as a case study in social app reinvention: the same brand and founders, an entirely different product built around small-group, real-time conversation rather than public broadcasting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '271e90eb-7f4a-4830-83c8-cbe9a8ca5270';

