-- ── Befonts ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Befonts is a font discovery website offering thousands of free and premium fonts curated for designers, with clear guidance on personal versus commercial licensing.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for personal-use fonts; premium and commercial fonts are priced individually by their creators$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Befonts: Free and Premium Fonts for Designers$q$, seo_title),
  seo_meta_description = COALESCE($q$Befonts curates thousands of free and premium fonts for designers, with clear personal-use and commercial-use licensing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Befonts, at befonts.com, is a font discovery and download website that curates typefaces for designers, offering a mix of free and premium fonts sourced from independent type designers. The site organizes its catalog by category, including serif, sans-serif, script, display, brush, and grotesque styles, and features dedicated sections such as Top Fonts, Free Fonts for Personal Use, Free Fonts for Commercial Use, and a directory of font designers whose work is featured on the platform. Befonts positions itself as a curation layer rather than a font foundry itself: the fonts listed are created and licensed by third-party designers, and Befonts surfaces and organizes them for visitors. Licensing on Befonts follows a two-tier model common to font marketplaces: many fonts are free for personal, non-commercial use only, while a separate, clearly labeled set of fonts is free for commercial use without additional licensing required for desktop use in a business setting; fonts intended for logo design, advertising, or products sold commercially generally require the buyer to purchase or verify a commercial license from the original designer. Because individual fonts are supplied by many different independent creators, licensing terms, and by extension pricing for premium or commercial licenses, vary font by font rather than following a single site-wide price list. Befonts has been used by a large volume of designers over the years and is commonly referenced alongside other font resource sites such as Google Fonts, DaFont, and Font Squirrel as a place to browse new and trending typefaces. The site does not publish detailed corporate information such as a founding date, headquarters, or team size, consistent with its identity as a content and curation website rather than a company with an enterprise sales presence. Befonts is best suited for graphic designers, web designers, and hobbyists looking to browse, preview, and download fonts for personal projects, with the option to pursue a commercial license for fonts used in paid or branded work.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '21dbbf18-b3b0-406f-8a88-055297fc15ab';

