-- ── Benchmark ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Benchmark is a Silicon Valley venture capital firm founded in 1995, known for early-stage bets on eBay, Twitter, Uber, Instagram, and Snapchat, and for its equal-partnership investment model.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(1995, founded_year),
  company_size = COALESCE($q$Small, about a dozen partners and staff$q$, company_size),
  headquarters = COALESCE($q$San Francisco and Woodside, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Benchmark: The VC Firm Behind eBay, Uber, and Twitter$q$, seo_title),
  seo_meta_description = COALESCE($q$Benchmark is a Silicon Valley VC firm founded in 1995, known for early bets on eBay, Twitter, Uber, and Snapchat. See its history and portfolio.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Benchmark, legally Benchmark Capital Advisors LLC and commonly known simply as Benchmark, is a venture capital firm founded in 1995 by Bob Kagle, Bruce Dunlevie, Andy Rachleff, Kevin Harvey, and Val Vaden. The firm is headquartered in San Francisco, with historical roots in nearby Woodside, California, and focuses on early-stage (seed and Series A) investing rather than growth-stage or late-stage rounds. Benchmark is widely regarded as one of the most successful and storied venture firms in Silicon Valley history. Its most famous early investment was a 6.7 million US dollar check for 22.1 percent of eBay in 1997, a stake that eventually returned more than 5 billion US dollars and helped establish Benchmark's reputation. Since then, Benchmark has been an early investor in a long list of category-defining companies, including Twitter, Instagram, Uber, Snapchat, Yelp, OpenTable, Zendesk, Zillow, New Relic, Elastic, Stitch Fix, Discord, and Juniper Networks, among many others. From 2011 onward, the firm counted more than 35 exits, including over a dozen IPOs and more than 20 mergers and acquisitions, representing tens of billions of dollars in realized value. Structurally, Benchmark is distinctive for operating as a flat, equal partnership: all general partners share ownership and compensation equally, with no managing partner, no senior-junior hierarchy, and no firm name built around a single founder, a deliberate departure from how most VC firms are organized. As of the mid-2020s, Benchmark's general partners include figures such as Peter Fenton, Eric Vishria, Sarah Tavel, Chetan Puttagunta, and Victor Lazarte, with the firm continuing to raise concentrated, relatively small funds by industry standards in order to preserve high per-partner ownership stakes in portfolio companies. Because Benchmark is a private investment partnership rather than a software product or service, it has no subscription pricing, no free trial, and no software features in the conventional sense; the firm's core activity is sourcing, evaluating, and funding early-stage startups in exchange for equity, then supporting portfolio companies through board seats and operational guidance. Benchmark does not publicly disclose fund sizes or assets under management with full consistency, though third-party estimates place total assets under management in the single-digit billions of US dollars, reflecting its strategy of staying deliberately small relative to peer mega-funds.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2fbffd64-ad25-4d61-8f29-f825da09e9de';

