-- ── Benevity ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Benevity is an enterprise corporate purpose platform that unifies employee giving, volunteering, grants management, and impact reporting for large employers.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom enterprise pricing; contact sales$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$About 750-850 employees$q$, company_size),
  headquarters = COALESCE($q$Calgary, Alberta, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Benevity: Corporate Giving and Volunteering Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Benevity is an enterprise CSR platform unifying employee giving, volunteering, and grants management. See features, pricing, and how it works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Benevity is an enterprise software platform for corporate social responsibility (CSR), employee giving, and workplace volunteering, founded in Calgary, Alberta, Canada in 2008 by Bryan de Lottinville. The company, marketed as the Benevity Enterprise Impact Platform, brings together employee giving, volunteering, grants and scholarship management, employee resource groups, engagement challenges, and impact reporting in a single system aimed at large employers. Benevity's core value proposition is consolidating what would otherwise be several disconnected CSR and engagement tools, such as matching-gift programs, volunteer time tracking, disaster relief campaigns, and nonprofit vetting, into one platform that integrates with a company's existing HR and payroll systems. The platform supports programs in more than 20 languages and connects employees to a large, pre-vetted network of nonprofit organizations worldwide, handling compliance and disbursement so companies do not need to manage individual donation payouts themselves. As of the mid-2020s, Benevity reports having processed more than 10 billion US dollars in donations and facilitated more than 46 million hours of tracked employee volunteering, supporting more than 326,000 nonprofit organizations, and has awarded more than 1.2 million grants through its platform. Benevity's customer base skews toward large, brand-name enterprises, and the company positions itself as a leading corporate purpose software provider, competing with platforms in the employee-giving and CSR space. Benevity does not publish self-serve or tiered subscription pricing; access is sold through custom enterprise contracts negotiated directly with the company, with pricing generally scaled to the size of the client organization and the specific mix of giving, volunteering, and grants modules deployed. Because implementations typically involve integration with a client's HR systems, payroll, and internal communications tools, onboarding is handled through Benevity's sales and customer success teams rather than a self-service signup flow. The company employs roughly 750 to 850 people globally as of the mid-2020s and operates from multiple offices in addition to its Calgary headquarters. Benevity is best suited for mid-size to large enterprises building or scaling a structured corporate social responsibility, employee giving, or volunteering program.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1cd3a1d9-5da9-4f4c-825e-94b1d362dd27';

