  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Better Uptime is Now Better Stack: What Changed$q$, seo_title),
  seo_meta_description = COALESCE($q$Better Uptime rebranded to Better Stack in 2023. See what its uptime monitoring, incident management, and status pages offer today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Better Uptime was the original name of a website, server, and API uptime monitoring product built by the company now known as Better Stack, headquartered in Prague, Czech Republic. The product first launched around 2020 as a Heroku add-on and standalone SaaS offering checks, incident alerting with phone call escalation, on-call scheduling, and hosted status pages. In 2023, the company rebranded its full product suite from Better Uptime and a companion log-management tool called Logtail to a unified platform called Better Stack, reflecting the company's expansion beyond uptime checks into logs, metrics, traces, dashboards, and broader incident management. Under the new branding, what used to be called Better Uptime is now marketed simply as Uptime, one module within the Better Stack platform, reachable at betterstack.com/uptime; the betteruptime.com domain and branding now point to this Better Stack product rather than a separate standalone service. Functionally, the uptime monitoring module checks websites, servers, APIs, SSL certificates, and heartbeats from monitoring locations on multiple continents, with check intervals as frequent as 30 seconds on paid plans and 3 minutes on the free plan. It includes incident management with phone, SMS, Slack, and Microsoft Teams alerting, on-call scheduling with escalation policies, Playwright-based synthetic transaction monitoring, and customizable public status pages. Better Stack offers a free plan covering up to 10 monitors and heartbeats, one status page, and basic Slack and email alerting, while paid plans begin at approximately 29 US dollars per month and add unlimited team members, phone and SMS alerts, faster check intervals, on-call escalation, SSO, SCIM, role-based access control, and audit logging; the company also advertises a 60-day money-back guarantee on paid plans. Better Stack integrates with common cloud and observability tools including AWS, Google Cloud, Microsoft Azure, Datadog, New Relic, Grafana, Prometheus, PagerDuty, and Opsgenie. Because the Better Uptime name persists in search traffic, documentation history, and third-party integrations such as its Heroku add-on listing, it is commonly treated as the predecessor brand or synonym for Better Stack's uptime monitoring product rather than a separate, currently marketed product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5ffdb2ec-9868-4c01-a2ab-458f8bba752a';

