-- ── Betterbird ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Betterbird is a free, open-source, donation-funded fork of Mozilla Thunderbird that closely tracks Thunderbird's ESR releases while adding extra features and faster bug fixes.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (donation-supported)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Solo maintainer with community contributors$q$, company_size),
  headquarters = COALESCE($q$Spain (project fiscal residence)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Betterbird: The Open-Source Thunderbird Fork$q$, seo_title),
  seo_meta_description = COALESCE($q$Betterbird is a free, donation-funded fork of Mozilla Thunderbird with extra features and faster bug fixes. See what it offers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Betterbird, available at betterbird.eu, is a free and open-source email client built as a soft fork of Mozilla Thunderbird. The project is led by Jorg Knobloch, a longtime Thunderbird contributor who served as Thunderbird's first paid employee and its maintainer and release engineer from roughly 2016 to 2019, contributing more than 2,000 commits to the official Thunderbird codebase before parting ways with the Thunderbird project over concerns about quality assurance and bug triage practices. Betterbird launched publicly around 2022 and has since released versions in parallel with Thunderbird's Extended Support Release (ESR) cycle, a deliberate strategy to avoid the fate of earlier Thunderbird forks that drifted from upstream and fell behind on security patches. Unlike a hard fork, Betterbird pulls its source directly from Mozilla's Thunderbird repositories and layers a public, transparent set of patches on top, published in a GitHub repository, with the stated goal of eventually contributing improvements back upstream to Thunderbird itself. Betterbird is distributed under the same MPL-2.0 open-source license as Thunderbird and runs on Windows, macOS, and Linux. Because it tracks the same profile format as Thunderbird, users can switch between Thunderbird and Betterbird on the same profile and version without conversion, making it a low-risk trial for existing Thunderbird users. Notable features added on top of stock Thunderbird include a multi-line message list view, an improved system tray tooltip on Linux showing new messages by folder, more powerful search with support for excluding criteria and regular expressions, and a feature that remembers recently used attachments so files can be reattached without re-browsing folders. Betterbird has no purchase price and carries no subscription fee; the project is entirely funded by voluntary donations processed through Stripe, PayPal, and regional bank transfer options across North America, Europe, the UK, Canada, and Australia and New Zealand. Reports indicate fewer than 2 percent of Betterbird's users financially support the project, with roughly half of donations coming from North America and half from Europe, particularly Germany. The project's fiscal residence is in Spain. Betterbird is best suited for existing Thunderbird users who want faster bug fixes, additional power-user features, and closer adherence to Thunderbird's official release cadence without waiting on Mozilla's own release and QA timeline.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e0905064-997b-4b5b-8fd6-50fee6bee0dd';

