INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Spectator Model$q$, $q$A semi-public mode where up to 50 core participants chat while outside spectators watch without joining, similar to a live readable podcast.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$No like counts or vanity metrics$q$, $q$Bebo removes public like counts and follower tallies to reduce popularity-contest dynamics.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Real-time messaging$q$, $q$Conversations happen live within a Crew rather than through a delayed, algorithmically ranked feed.$q$, 3);
