INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Is Bebo still around in 2026?$q$, $q$Yes. Bebo has been relaunched by its original founders, Michael and Xochi Birch, as a free group chat app built around private Crews.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Who owns Bebo now?$q$, $q$Bebo is owned and operated by its original co-founders, Michael and Xochi Birch, who bought the brand back in 2013.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Is Bebo free to use?$q$, $q$Yes, Bebo is free for individual members with no subscription fee to create or join a Crew.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$What happened to the original Bebo social network?$q$, $q$The original Bebo, launched in 2005, was sold to AOL in 2008 for roughly 850 million US dollars, then sold off to Criterion Capital Partners in 2010 before the Birches repurchased it in 2013.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$What is a Crew in Bebo?$q$, $q$A Crew is a private group chat of up to about 100 people, functioning as the core social unit of the current Bebo app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$What is the Spectator Model?$q$, $q$The Spectator Model lets a Crew go semi-public so outside viewers can watch a live conversation among core members without participating unless invited.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Has Bebo shut down before?$q$, $q$Yes, prior relaunches, including a mobile social and livestreaming app around 2017, and a later private-beta version, were both discontinued before the current relaunch.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Is Bebo available as a mobile app?$q$, $q$Access options have varied across Bebo's relaunches, so check bebo.com directly for the current availability of web or mobile access.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Close friend group chat$q$, $q$Small groups use Crews to stay in touch with real-time chat instead of a public social feed.$q$, $q$Friend groups and small communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Nostalgic reconnection$q$, $q$Former users of the original 2000s Bebo network revisit the brand under its new, founder-led relaunch.$q$, $q$Former Bebo users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Alternative to algorithmic social feeds$q$, $q$Privacy-conscious users seeking a chat app without like counts or feed algorithms use Bebo's Crew-based model.$q$, $q$Privacy-conscious social media users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Create or join Crews","Real-time group chat","Spectator Model public viewing","No subscription required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$overview$q$, $q$What Is Bebo$q$, 2, ARRAY[$q$Bebo is a free social app currently owned and operated by its original founders, Michael and Xochi Birch, who first launched the Bebo social network in January 2005 from their home in San Francisco. The early Bebo grew rapidly through the mid-2000s and became one of the largest social networks of its era, competing directly with MySpace and Facebook before AOL acquired it in March 2008 for roughly 850 million US dollars.$q$, $q$AOL was unable to sustain Bebo's growth, and the network was sold to Criterion Capital Partners in 2010 before the Birches bought it back for around 1 million US dollars in 2013. Since then, the founders have relaunched Bebo multiple times under different concepts, including a 2014 video walkie-talkie app called Blab and a mobile social and livestreaming app released around 2017 that was discontinued by roughly 2019-2020 after limited adoption; a further private-beta attempt was also shut down by 2022.$q$, $q$The current iteration of Bebo, rolled out in stages through the mid-2020s, is a deliberate departure from both the original network and typical modern social apps: it removes public newsfeeds, follower counts, and like buttons, and instead centers on small, private group conversations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bebo's core unit is the Crew, a private group chat of up to roughly 100 people designed for close friend groups rather than broad public audiences. Crews function as real-time chat rooms where members share updates, photos, and conversation without an algorithmic feed sorting or ranking the content.$q$, $q$A companion feature called the Spectator Model lets a Crew opt into a semi-public mode, functioning like a live, readable podcast: a core group of up to 50 participants carries the conversation while outside spectators can watch in real time without being able to join in unless invited.$q$, $q$By removing like counts and other vanity metrics, Bebo aims to reduce the popularity-contest dynamics and algorithmic engagement pressure associated with mainstream social platforms, positioning itself as a calmer alternative for staying in touch with a small circle of people.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('271e90eb-7f4a-4830-83c8-cbe9a8ca5270', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bebo is free for individual members. There is no subscription fee to create or join a Crew, and no premium tier has been publicized as part of the current relaunch.$q$, $q$Because Bebo has gone through several relaunches and shutdowns since regaining independence in 2013, prospective users should treat it as an independent, founder-funded project rather than a mainstream platform with guaranteed long-term continuity, and should check bebo.com directly for the most current feature set and availability.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Multi-source data harmonization$q$, $q$Combines syndicated data from Nielsen, Circana/IRI, SPINS, and NPD with retailer POS, panel, and e-commerce data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$AI-powered insights$q$, $q$Integrates models such as ChatGPT, Claude, and Llama for natural-language querying and AI-assisted reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$30+ CPG visualizations$q$, $q$Prebuilt, CPG-specific charts and visual reporting formats for retail sales data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Automated sales deck creation$q$, $q$Generates presentation-ready sales decks from platform data automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Customizable dashboards$q$, $q$Dashboards can be tailored to specific categories, retailers, or teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Promotion and pricing analysis$q$, $q$Tools for analyzing promotional lift, pricing strategy, and category performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$350+ product category coverage$q$, $q$Supports analytics across a broad range of CPG categories, including cannabis.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Dedicated category manager support$q$, $q$Access to a support team of more than 15 in-house category managers with live chat.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Unifies fragmented retail data sources into one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Strong coverage of the cannabis and broader CPG categories$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$AI-assisted reporting reduces manual analyst work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Dedicated category manager support team$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Highly customizable dashboards and visualizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Pricing is not transparent and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Cost scales with data complexity, which can raise cost for larger data footprints$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Primarily suited to CPG and retail teams rather than general-purpose BI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Onboarding requires integrating multiple data providers, which can take time$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$What is Bedrock Analytics used for?$q$, $q$Bedrock Analytics is used by CPG brands and manufacturers to harmonize retail and syndicated sales data into dashboards, visualizations, and AI-assisted reporting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Does Bedrock Analytics only serve the cannabis industry?$q$, $q$No. Bedrock is positioned as a general CPG analytics platform covering 350+ categories, though it has strong recognition and coverage within the cannabis industry.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$What data sources does Bedrock Analytics integrate?$q$, $q$It integrates syndicated data providers such as Nielsen, Circana/IRI, SPINS, and NPD, along with retailer point-of-sale, panel, and e-commerce data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$How much does Bedrock Analytics cost?$q$, $q$Bedrock does not publish fixed pricing; cost is based on categories, data providers, retail portals, users, and segmentation level, with quotes provided directly by Bedrock's sales team.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Does Bedrock Analytics use AI?$q$, $q$Yes, the platform integrates a multi-model AI stack referencing ChatGPT, Claude, and Llama for insight generation and reporting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Who is Bedrock Analytics for?$q$, $q$It is designed for CPG brand analytics, sales, and category management teams that need a unified view of retail sales data.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Where is Bedrock Analytics based?$q$, $q$Bedrock Analytics is headquartered in Oakland, California, in the San Francisco Bay Area.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$How many product categories does Bedrock Analytics cover?$q$, $q$Bedrock covers more than 350 product categories across CPG and cannabis retail data.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Cannabis brand retail analytics$q$, $q$Cannabis CPG brands use Bedrock to harmonize retail sales data that is otherwise fragmented across data providers.$q$, $q$Cannabis CPG brands and category managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$CPG sales and category management reporting$q$, $q$Sales and category teams use Bedrock's dashboards to replace manual spreadsheet-based retail reporting.$q$, $q$CPG sales and category management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Automated retail sales presentations$q$, $q$Marketing and sales leadership use Bedrock's automated deck generation to prepare retailer-facing presentations.$q$, $q$CPG marketing and sales leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$Custom$q$, $q$Contact sales$q$, $q$Annual/custom$q$, NULL, $q$["Pricing based on categories, data providers, retail portals, and users","10 users included, additional users from $50 to $100 per month","20, 50, or 100 segment options","Access to category manager support team"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$overview$q$, $q$What Is Bedrock Analytics$q$, 2, ARRAY[$q$Bedrock Analytics is a cloud-based consumer packaged goods (CPG) analytics platform founded in 2013 and headquartered in Oakland, California, in the San Francisco Bay Area. The company was built by a team combining CPG industry veterans and Silicon Valley technologists to help brands and manufacturers extract more value from retail sales data.$q$, $q$The platform harmonizes data from major syndicators, including Nielsen, Circana/IRI, SPINS, and NPD, together with retailer point-of-sale, panel, and e-commerce data, into a single reporting layer. Bedrock covers more than 350 product categories, and it has become particularly associated with the cannabis industry, where standardized retail data has historically been harder to access than in more established CPG categories, though the platform is positioned as a general CPG analytics solution rather than a cannabis-only tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include more than 30 CPG-specific data visualizations, customizable dashboards, promotion and pricing analysis, and automated sales deck generation intended to replace manual spreadsheet work for category managers and sales teams.$q$, $q$Bedrock has layered in a multi-model AI stack, referencing integration with models such as ChatGPT, Claude, and Llama, to support natural-language querying and AI-assisted narrative generation from retail data, alongside access to a support team described as more than 15 in-house category managers offering live chat support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f541863-33e8-4350-b428-5a3b7fa112fb', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bedrock Analytics does not publish fixed subscription tiers. Instead, pricing is quote-based and tied to five factors: the number of product categories in scope, the number of connected data providers and syndicators, the number of integrated retail portals, the number of user accounts, and the chosen level of market segmentation (20, 50, or 100 aggregate segments).$q$, $q$Ten user accounts are included by default, with additional users billed at roughly 100 US dollars per month each up to 20 total users, and 50 US dollars per month per user beyond that. Prospective customers need to contact Bedrock directly through its website to receive a personalized quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Custom FileMaker/Claris app development$q$, $q$Builds custom business applications on the Claris FileMaker platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Claris Platinum Partner status$q$, $q$Holds the top partner tier in the Claris/FileMaker ecosystem, with multiple Claris Excellence Awards.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Data integration and migration services$q$, $q$Helps organizations migrate and integrate legacy data into modern systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Web development$q$, $q$Builds web applications using JavaScript-based stacks.$q$, 3);
