INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Proprietary FileMaker plugins and tools$q$, $q$Develops and distributes its own plugins and tools for the FileMaker platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Long-term client support and maintenance$q$, $q$Provides ongoing support for custom applications after launch.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Deep FileMaker/Claris expertise as a Platinum Partner$q$, 0);
