INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Long track record dating back to 1996$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Award-winning team recognized by Claris$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Strong reputation within the FileMaker developer community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Not a self-serve software product; requires a custom engagement$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$No published pricing, requiring direct contact for quotes$q$, 1);
