INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Best fit is narrower, mainly FileMaker-centric organizations and custom software buyers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$What does Beezwax Datatools do?$q$, $q$Beezwax Datatools is a custom software and data consultancy specializing in Claris FileMaker development, along with web, Ruby on Rails, and iOS app development.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Is Beezwax a software product or a consulting firm?$q$, $q$Beezwax is primarily a consulting and development firm, though it also builds and sells its own FileMaker plugins and tools.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$What is a Claris Platinum Partner?$q$, $q$Claris Platinum Partner is the highest partner tier awarded by Claris (the maker of FileMaker) to development firms with proven expertise and track record.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$What technologies does Beezwax work with besides FileMaker?$q$, $q$Beezwax also works with JavaScript, Ruby on Rails, and iOS development for web and mobile projects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$How much does Beezwax charge for a project?$q$, $q$Beezwax does not publish fixed rates; pricing is quoted per project based on scope and requirements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$How long has Beezwax been in business?$q$, $q$Beezwax Datatools has operated since 1996.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Where is Beezwax located?$q$, $q$Beezwax is headquartered in the San Francisco Bay Area, California, with a distributed team serving clients nationally and internationally.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Does Beezwax offer ongoing support after a project launches?$q$, $q$Yes, Beezwax provides long-term support and maintenance for the custom applications it builds.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Custom FileMaker application development$q$, $q$Businesses running Claris FileMaker use Beezwax to build and extend custom internal applications.$q$, $q$Businesses running Claris FileMaker$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Legacy database modernization$q$, $q$Organizations use Beezwax to migrate and modernize older data systems into current platforms.$q$, $q$Companies migrating legacy data systems$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$Full-stack custom software builds$q$, $q$Small and mid-size businesses use Beezwax for combined web, mobile, and iOS application development.$q$, $q$SMBs needing custom web and mobile apps$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$overview$q$, $q$What Is Beezwax Datatools$q$, 2, ARRAY[$q$Beezwax Datatools, Inc. is a custom software development and data consultancy headquartered in the San Francisco Bay Area that has operated since 1996, making it one of the longer-running independent firms in the Claris FileMaker ecosystem. The company works with clients throughout the United States and internationally through a distributed team.$q$, $q$Across its history, Beezwax reports completing more than 2,000 custom data, web, mobile, and analytics projects for over 600 clients, with its core specialization in Claris FileMaker application development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beezwax holds Claris Platinum Partner status, the top partner tier in the Claris/FileMaker ecosystem, and has received Claris Excellence Awards for both Advocacy and Lifetime Achievement; longtime team member Vincenzo (Vince) Menanno has been recognized for more than 30 years of FileMaker community leadership.$q$, $q$Beyond FileMaker, Beezwax's team also works in JavaScript, Ruby on Rails, and iOS app development, and the company builds and maintains its own proprietary plugins and tools for the FileMaker platform, which it distributes alongside its client consulting practice.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41edfd95-63c6-404d-94c9-c87a98ef19f2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Beezwax is fundamentally a services and consulting business rather than a self-serve SaaS product, so it does not publish fixed subscription pricing. Engagements are quoted per project based on scope, timeline, and the mix of custom development, data migration, or ongoing support required, and prospective clients need to contact Beezwax directly for an estimate.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Large free font library$q$, $q$Thousands of free fonts across a wide range of design styles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Premium and commercial font marketplace$q$, $q$Curated premium fonts with commercial licensing available for purchase.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Category browsing$q$, $q$Fonts organized by style, including serif, sans-serif, script, display, brush, and grotesque.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Personal-use versus commercial-use filters$q$, $q$Dedicated sections separate fonts licensed for personal use from those cleared for commercial use.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Font designer directory$q$, $q$Profiles the independent type designers whose fonts are featured on the site.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Top and trending fonts lists$q$, $q$Highlights popular and newly added fonts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Direct font preview and download$q$, $q$Lets visitors preview typefaces before downloading.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Large curated font library across many styles$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Clear distinction between personal-use and commercial-use fonts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Supports independent type designers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Simple category-based browsing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Free tier available for personal projects$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Licensing terms vary font by font, requiring users to check each one individually$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Some fonts require a separate purchase for commercial use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Limited public transparency on company founding, ownership, or team size$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Quality and support vary since fonts are supplied by many different third-party designers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Is Befonts free?$q$, $q$Many fonts on Befonts are free for personal use, while other fonts are premium or require a commercial license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Can I use Befonts fonts commercially?$q$, $q$It depends on the specific font; Befonts labels fonts that are free for commercial use separately from personal-use-only fonts, and some premium fonts require a purchased license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Who makes the fonts on Befonts?$q$, $q$The fonts are created by independent, third-party type designers whose work Befonts curates and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$What is Befonts?$q$, $q$Befonts is a website that curates and offers free and premium fonts for designers to browse and download.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$What types of fonts does Befonts offer?$q$, $q$Befonts organizes fonts by style, including serif, sans-serif, script, display, brush, and grotesque typefaces.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$How is Befonts different from a type foundry?$q$, $q$Befonts does not design fonts itself; it curates and distributes fonts created by independent designers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Is Befonts good for logo design fonts?$q$, $q$Fonts used in logo design or commercial products generally require a commercial license, which Befonts labels separately from personal-use fonts.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Does Befonts charge for premium fonts?$q$, $q$Yes, premium and commercial fonts are priced individually by their designers rather than through a single site-wide fee.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Personal design projects$q$, $q$Hobbyists and students download free, personal-use fonts for non-commercial projects.$q$, $q$Hobbyist designers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Commercial branding and marketing materials$q$, $q$Graphic designers and agencies license commercial-use fonts for client branding work.$q$, $q$Graphic designers and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Web and UI typography exploration$q$, $q$Web designers browse Befonts to find new typefaces for websites and interfaces.$q$, $q$Web designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Free (Personal Use)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Access to fonts licensed for personal, non-commercial use","Category and top-fonts browsing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$Commercial/Premium Fonts$q$, $q$Varies by font$q$, $q$One-time per font license$q$, NULL, $q$["Fonts licensed for commercial and business use","Pricing and terms set individually by each font designer"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$overview$q$, $q$What Is Befonts$q$, 2, ARRAY[$q$Befonts, at befonts.com, is a font discovery and download website that curates typefaces for designers, combining free and premium fonts sourced from independent type designers rather than producing fonts itself.$q$, $q$The site organizes its catalog into categories such as serif, sans-serif, script, display, brush, and grotesque styles, and includes dedicated sections like Top Fonts, Free Fonts for Personal Use, Free Fonts for Commercial Use, and a directory profiling the individual font designers featured on the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Licensing on Befonts follows a two-tier model common to font marketplaces: many fonts are free for personal, non-commercial use only, while a separate, clearly labeled set of fonts is free for commercial use without additional licensing required for standard desktop use in a business setting.$q$, $q$Fonts intended for logo design, advertising, or products sold commercially generally require purchasing or verifying a commercial license from the original designer. Because many independent creators supply fonts to the site, licensing terms, and pricing for premium or commercial licenses, vary font by font rather than following one site-wide price list.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21dbbf18-b3b0-406f-8a88-055297fc15ab', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Befonts itself does not charge a platform-wide subscription fee. Personal-use fonts are free to download, while commercial and premium fonts are priced individually by their respective designers, and buyers purchase or license those fonts directly through the relevant font page.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Equal-partnership investment model$q$, $q$All general partners share ownership and compensation equally, with no hierarchy of senior or junior partners.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Early-stage focus$q$, $q$Concentrates primarily on seed and Series A investments rather than growth or late-stage rounds.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Board-level involvement$q$, $q$General partners typically take board seats and provide hands-on support to founders.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Concentrated portfolio strategy$q$, $q$Makes fewer, larger bets rather than spreading investment across a very large number of companies.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Sector-agnostic technology investing$q$, $q$Invests across consumer, enterprise, and marketplace technology companies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Track record of major exits$q$, $q$Backed companies including eBay, Twitter, Uber, Instagram, and Snapchat through to IPO or acquisition.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$No associate or junior-investor layer$q$, $q$Deal sourcing and evaluation are handled directly by general partners rather than junior staff.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Deliberately small fund sizes$q$, $q$Raises smaller funds relative to peers to preserve high ownership stakes per portfolio company.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Highly selective, high-signal backing for portfolio founders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Hands-on senior partner involvement with no associate layer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Track record including massive exits like eBay, Uber, and Twitter$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Flat, equal-partner structure that aligns partner incentives$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Concentrated portfolio allows deeper support per company$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Extremely selective, making it difficult for most startups to get funded$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Primarily deal-flow driven through warm introductions rather than open applications$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Does not run large-scale growth or late-stage follow-on investing like mega-funds$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Small firm size limits the number of companies it can actively support at once$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$What is Benchmark?$q$, $q$Benchmark is a Silicon Valley venture capital firm founded in 1995 that invests primarily in early-stage technology startups.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$What stage does Benchmark invest in?$q$, $q$Benchmark focuses primarily on seed and Series A stage investments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$What companies has Benchmark backed?$q$, $q$Notable Benchmark investments include eBay, Twitter, Instagram, Uber, Snapchat, Yelp, OpenTable, and Zendesk, among many others.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Who founded Benchmark?$q$, $q$Benchmark was founded in 1995 by Bob Kagle, Bruce Dunlevie, Andy Rachleff, Kevin Harvey, and Val Vaden.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$What makes Benchmark's partnership structure unique?$q$, $q$Benchmark operates as a flat, equal partnership where all general partners share ownership and compensation equally, without a managing partner or junior-investor hierarchy.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$How much does Benchmark manage?$q$, $q$Benchmark does not consistently disclose exact fund sizes, though third-party estimates place its assets under management in the single-digit billions of US dollars.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Where is Benchmark based?$q$, $q$Benchmark is headquartered in San Francisco, California, with historical roots in Woodside, California.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$How do founders get funding from Benchmark?$q$, $q$Benchmark typically evaluates and funds startups through direct relationships and warm introductions to its general partners rather than an open application process.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Seed-stage fundraising$q$, $q$Early-stage founders seek Benchmark as a lead investor for their seed round.$q$, $q$Early-stage startup founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Series A fundraising with board support$q$, $q$Startups scaling past seed raise Series A capital from Benchmark along with hands-on board involvement.$q$, $q$Startups scaling post-seed$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$Studying venture capital firm structure$q$, $q$Investors, LPs, and business researchers study Benchmark's equal-partnership model as a case study in VC firm design.$q$, $q$Investors and business researchers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$overview$q$, $q$What Is Benchmark$q$, 2, ARRAY[$q$Benchmark, legally Benchmark Capital Advisors LLC, is a venture capital firm founded in 1995 by Bob Kagle, Bruce Dunlevie, Andy Rachleff, Kevin Harvey, and Val Vaden. The firm is headquartered in San Francisco, with historical roots in nearby Woodside, California, and focuses on early-stage investing, primarily seed and Series A rounds.$q$, $q$Benchmark is widely regarded as one of the most successful venture firms in Silicon Valley history. Its most famous early investment was a 6.7 million US dollar check for 22.1 percent of eBay in 1997, a stake that eventually returned more than 5 billion US dollars and helped establish the firm's reputation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$key-features$q$, $q$How Benchmark Invests$q$, 2, ARRAY[$q$Since its eBay investment, Benchmark has been an early backer of a long list of category-defining companies, including Twitter, Instagram, Uber, Snapchat, Yelp, OpenTable, Zendesk, Zillow, New Relic, Elastic, Stitch Fix, and Discord, among many others. From 2011 onward, the firm recorded more than 35 exits, including over a dozen IPOs and more than 20 mergers and acquisitions.$q$, $q$Structurally, Benchmark is distinctive for operating as a flat, equal partnership: all general partners share ownership and compensation equally, with no managing partner, no senior-junior hierarchy, and no associate or junior-investor layer, a deliberate departure from how most VC firms are organized. As of the mid-2020s, Benchmark's general partners include Peter Fenton, Eric Vishria, Sarah Tavel, Chetan Puttagunta, and Victor Lazarte.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2fbffd64-ad25-4d61-8f29-f825da09e9de', $q$pricing$q$, $q$Fund Structure$q$, 2, ARRAY[$q$Benchmark is a private investment partnership, not a software product, so it has no subscription pricing, free trial, or purchasable plan. Instead, Benchmark invests its own managed funds directly into startups in exchange for equity, typically taking a board seat and providing hands-on operational support to portfolio companies.$q$, $q$The firm deliberately raises smaller, more concentrated funds than many peer mega-funds in order to preserve high per-partner ownership stakes in each portfolio company; third-party estimates place its total assets under management in the single-digit billions of US dollars, though Benchmark does not consistently disclose exact fund sizes.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Employee giving and matching gifts$q$, $q$Lets employees donate to nonprofits with employer-matched contributions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Volunteering time tracking$q$, $q$Tracks and reports employee volunteer hours across programs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Grants and scholarship management$q$, $q$Manages corporate grant and scholarship programs end to end.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Employee resource group support$q$, $q$Provides tools for organizing and engaging employee resource groups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Engagement challenges and campaigns$q$, $q$Supports company-wide giving and volunteering campaigns and challenges.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Impact reporting and analytics$q$, $q$Generates reporting on giving, volunteering, and overall program impact for ESG disclosures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Global nonprofit vetting network$q$, $q$Connects employees to a pre-vetted network of more than 326,000 nonprofit organizations worldwide.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Multi-language support$q$, $q$Supports corporate giving and volunteering programs in more than 20 languages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Consolidates multiple CSR programs into a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Large, pre-vetted nonprofit network reduces compliance burden$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Strong reporting and analytics for ESG disclosures$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Trusted by many large, brand-name enterprises$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Supports global, multi-language workforces$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Enterprise-only pricing not accessible to small businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Pricing is not published and requires a sales engagement$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Implementation requires HR and payroll integration work$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$May be more platform than smaller organizations need$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$What is Benevity used for?$q$, $q$Benevity is used by enterprises to manage employee giving, volunteering, grants, and corporate social responsibility reporting in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Who founded Benevity and when?$q$, $q$Benevity was founded in Calgary, Alberta, Canada in 2008 by Bryan de Lottinville.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$How much does Benevity cost?$q$, $q$Benevity does not publish fixed pricing; it sells custom enterprise contracts scaled to organization size and modules used.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$What is the Benevity Enterprise Impact Platform?$q$, $q$It is Benevity's unified product covering employee giving, volunteering, grants management, employee resource groups, and impact reporting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Does Benevity support corporate volunteering?$q$, $q$Yes, Benevity includes tools for tracking and reporting employee volunteer hours.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$How many nonprofits are on Benevity's network?$q$, $q$Benevity connects to a pre-vetted network of more than 326,000 nonprofit organizations worldwide.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Is Benevity only for large companies?$q$, $q$Benevity's enterprise pricing and implementation model make it best suited for mid-size to large organizations rather than very small businesses.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Where is Benevity headquartered?$q$, $q$Benevity is headquartered in Calgary, Alberta, Canada.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Corporate employee giving programs$q$, $q$HR and CSR teams use Benevity to run and manage employee donation and matching-gift programs.$q$, $q$HR and CSR teams at large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Employee volunteering tracking$q$, $q$Corporate social impact teams track and report employee volunteer hours through Benevity.$q$, $q$Corporate social impact teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Grants and scholarship administration$q$, $q$Corporate foundations manage grant and scholarship programs using Benevity's tools.$q$, $q$Corporate foundations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["Employee giving and matching","Volunteering tracking","Grants management","Impact reporting","Access to vetted nonprofit network"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$overview$q$, $q$What Is Benevity$q$, 2, ARRAY[$q$Benevity is an enterprise software platform for corporate social responsibility (CSR), employee giving, and workplace volunteering, founded in Calgary, Alberta, Canada in 2008 by Bryan de Lottinville. The company markets its product as the Benevity Enterprise Impact Platform.$q$, $q$The platform brings together employee giving, volunteering, grants and scholarship management, employee resource groups, engagement challenges, and impact reporting in a single system aimed at large employers, consolidating tools that would otherwise be spread across multiple disconnected vendors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Benevity supports programs in more than 20 languages and connects employees to a large, pre-vetted network of nonprofit organizations, handling compliance and payout disbursement so companies do not need to manage individual donations themselves. As of the mid-2020s, Benevity reports having processed more than 10 billion US dollars in donations and facilitated over 46 million hours of tracked employee volunteering across more than 326,000 nonprofit organizations, with more than 1.2 million grants awarded through the platform.$q$, $q$Because implementations typically integrate with a client's HR systems, payroll, and internal communications tools, Benevity's customer base skews toward mid-size to large, brand-name enterprises, and onboarding is handled through the company's sales and customer success teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1cd3a1d9-5da9-4f4c-825e-94b1d362dd27', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Benevity does not publish self-serve or tiered subscription pricing. Access is sold through custom enterprise contracts negotiated directly with the company, generally scaled to organization size and the specific mix of giving, volunteering, and grants modules deployed, with prospective customers required to request a demo and quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Website, server, and API uptime monitoring$q$, $q$Checks endpoints from multiple global regions with intervals as fast as 30 seconds on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Incident management and alerting$q$, $q$Sends phone, SMS, Slack, and Microsoft Teams alerts when incidents occur.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$On-call scheduling and escalation$q$, $q$Supports on-call rotations with escalation policies for incident response teams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Hosted, customizable status pages$q$, $q$Public status pages that can be branded and customized per company.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Synthetic transaction monitoring$q$, $q$Uses Playwright-based scripted checks to test multi-step user flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$SSL certificate and heartbeat monitoring$q$, $q$Monitors certificate expiry and scheduled/cron job heartbeats.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Multi-region checks$q$, $q$Runs checks from monitoring locations across multiple continents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Third-party integrations$q$, $q$Connects with AWS, Google Cloud, Azure, Datadog, Grafana, PagerDuty, and other tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Generous free tier covering 10 monitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Fast 30-second check intervals on paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Combines uptime monitoring with broader observability under one account$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Reliable phone-call incident alerting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Well-regarded, customizable status pages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Full observability suite (logs and metrics) is priced separately from uptime monitoring$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Brand confusion persists from the Better Uptime to Better Stack rebrand$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Enterprise features like SSO, SCIM, and RBAC require higher-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Some advanced monitoring features are gated behind paid tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Is Better Uptime still a separate product?$q$, $q$No. Better Uptime was rebranded to Better Stack in 2023, and its functionality now lives as the Uptime module within the Better Stack platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$What happened to Better Uptime?$q$, $q$Better Uptime, along with the Logtail log-management tool, was rebranded and merged into the unified Better Stack platform in 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Is Better Stack free?$q$, $q$Yes, Better Stack offers a free plan covering up to 10 monitors and heartbeats, one status page, and basic alerting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$How much does Better Stack's uptime monitoring cost?$q$, $q$Paid uptime monitoring plans start at approximately 29 US dollars per month, with enterprise tiers priced separately.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Does Better Uptime still work as a Heroku add-on?$q$, $q$The Better Uptime name is still associated with a legacy Heroku add-on listing, which now maps to Better Stack's uptime monitoring product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$What is the difference between Better Uptime and Better Stack?$q$, $q$They are the same underlying company and product line; Better Uptime was the original brand, and Better Stack is the current, expanded branding covering uptime, logs, metrics, and incident management.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Where is Better Stack headquartered?$q$, $q$Better Stack is headquartered in Prague, Czech Republic.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$What features does Better Stack's uptime monitoring include?$q$, $q$It includes multi-region uptime checks, incident alerting, on-call scheduling, synthetic transaction monitoring, and hosted status pages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Website and API uptime monitoring$q$, $q$Engineering and DevOps teams monitor production websites and APIs for downtime.$q$, $q$Engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Incident response and on-call management$q$, $q$SRE and operations teams use on-call scheduling and escalation to manage incidents.$q$, $q$SRE and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Public status page hosting$q$, $q$SaaS companies use hosted status pages to communicate uptime and incidents to customers.$q$, $q$SaaS companies and their customers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["10 monitors and heartbeats","1 status page","3-minute check intervals","Slack and email alerts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Paid (Uptime)$q$, $q$From $29 per month$q$, $q$Monthly or annual$q$, NULL, $q$["30-second check intervals","Unlimited team members","Phone and SMS alerts","On-call scheduling and escalations","Playwright-based transaction checks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["SSO and SCIM","Role-based access control","Audit logs","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$overview$q$, $q$What Is Better Uptime (Better Stack)$q$, 2, ARRAY[$q$Better Uptime was the original name of a website, server, and API uptime monitoring product built by the company now known as Better Stack, headquartered in Prague, Czech Republic. The product launched around 2020, initially gaining traction partly through a Heroku add-on listing, and offered uptime checks, incident alerting with phone-call escalation, on-call scheduling, and hosted status pages.$q$, $q$In 2023, the company rebranded its full product suite, including Better Uptime and a companion log-management tool called Logtail, into a unified platform called Better Stack, reflecting its expansion beyond uptime checks into logs, metrics, traces, dashboards, and broader incident management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Under the current branding, what used to be marketed as Better Uptime is now the Uptime module within Better Stack, reachable at betterstack.com/uptime; the betteruptime.com brand still commonly refers to this same product. It checks websites, servers, APIs, SSL certificates, and heartbeats from monitoring locations across multiple continents, with check intervals as fast as 30 seconds on paid plans and 3 minutes on the free plan.$q$, $q$The product includes incident management with phone, SMS, Slack, and Microsoft Teams alerting, on-call scheduling with escalation policies, Playwright-based synthetic transaction monitoring, and customizable public status pages, plus integrations with tools such as AWS, Google Cloud, Microsoft Azure, Datadog, New Relic, Grafana, Prometheus, PagerDuty, and Opsgenie.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5ffdb2ec-9868-4c01-a2ab-458f8bba752a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Better Stack offers a free plan covering up to 10 monitors and heartbeats, one status page, and basic Slack and email alerting. Paid plans begin at roughly 29 US dollars per month and add unlimited team members, phone and SMS alerts, faster 30-second check intervals, on-call escalation, and Playwright-based transaction checks.$q$, $q$Higher enterprise tiers add SSO, SCIM, role-based access control, audit logging, and advanced reporting, typically at custom pricing. The company also advertises a 60-day money-back guarantee on its paid plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Multi-line message list view$q$, $q$Displays multiple lines of message information in the list view, a long-requested Thunderbird feature.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Enhanced system tray tooltips$q$, $q$Shows new messages by folder in the system tray on Linux.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Advanced search$q$, $q$Supports regular expressions and exclusion criteria in complex mail searches.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Recently-used attachments memory$q$, $q$Lets users reattach recently used files without browsing folders again.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Close ESR tracking with faster fixes$q$, $q$Follows Thunderbird's Extended Support Release cycle while shipping bug fixes faster than upstream.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Cross-platform support$q$, $q$Runs on Windows, macOS, and Linux.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Profile compatibility with Thunderbird$q$, $q$Uses the same profile format, allowing easy switching between Thunderbird and Betterbird.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Public, transparent patch repository$q$, $q$Publishes all applied patches openly on GitHub.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Completely free with no paywalled features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Faster bug fixes than stock Thunderbird$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Easy to trial since it shares Thunderbird profiles$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Transparent, publicly reviewable patches$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Maintained by a Thunderbird industry veteran$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Stays close to upstream to avoid security drift$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Run mainly by a single lead maintainer, creating a bus-factor risk$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Funded almost entirely by a small percentage of donating users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Smaller team may respond more slowly to some edge-case bugs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Not officially affiliated with or supported by Mozilla$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Is Betterbird free?$q$, $q$Yes, Betterbird is free and open-source, funded entirely through voluntary donations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Who created Betterbird?$q$, $q$Betterbird is led by Jorg Knobloch, a former Thunderbird maintainer and release engineer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Is Betterbird safe and legitimate?$q$, $q$Betterbird is a soft fork that sources code directly from Mozilla's Thunderbird repositories and publishes its patches publicly on GitHub, closely tracking Thunderbird's ESR releases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Can I switch between Thunderbird and Betterbird easily?$q$, $q$Yes, both clients share the same profile format, so users can switch between them on the same version without conversion.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$What platforms does Betterbird support?$q$, $q$Betterbird runs on Windows, macOS, and Linux.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Does Betterbird share code with Thunderbird?$q$, $q$Yes, Betterbird's source is pulled directly from Mozilla's Thunderbird repositories, with additional patches layered on top.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Does Betterbird contribute changes back to Thunderbird?$q$, $q$Yes, the project's stated goal is to submit its improvements upstream so Thunderbird itself can eventually benefit.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$How is Betterbird funded?$q$, $q$Betterbird is funded entirely by voluntary donations via Stripe, PayPal, and regional bank transfers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Power-user email management$q$, $q$Desktop email users adopt Betterbird for features like multi-line view and advanced search not yet in stock Thunderbird.$q$, $q$Desktop email power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Faster bug-fix adoption$q$, $q$Thunderbird users frustrated by slow official fixes switch to Betterbird for quicker patches.$q$, $q$Existing Thunderbird users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Privacy-conscious open-source email use$q$, $q$Privacy-focused individuals and organizations choose Betterbird as an open-source desktop email client.$q$, $q$Privacy-focused individuals and organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$Free / Open Source$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full email client functionality","Cross-platform support","Community and donation-based support","Optional donations to fund development"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$overview$q$, $q$What Is Betterbird$q$, 2, ARRAY[$q$Betterbird, available at betterbird.eu, is a free and open-source email client built as a soft fork of Mozilla Thunderbird. The project is led by Jorg Knobloch, a longtime Thunderbird contributor who served as Thunderbird's first paid employee and its maintainer and release engineer from roughly 2016 to 2019, contributing more than 2,000 commits to the official Thunderbird codebase.$q$, $q$Betterbird launched publicly around 2022 after Knobloch parted ways with the official Thunderbird project over concerns about quality assurance and bug-triage practices, and has since released versions in parallel with Thunderbird's Extended Support Release (ESR) cycle.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Unlike a hard fork, Betterbird pulls its source directly from Mozilla's Thunderbird repositories and layers a public, transparent set of patches on top, published in a GitHub repository, with the stated goal of eventually contributing improvements back upstream to Thunderbird itself. It is distributed under the same MPL-2.0 license as Thunderbird and runs on Windows, macOS, and Linux, sharing the same profile format so users can switch between the two clients on the same version without conversion.$q$, $q$Notable features layered on top of stock Thunderbird include a multi-line message list view, an improved system tray tooltip on Linux that shows new messages by folder, more powerful search with support for excluding criteria and regular expressions, and a feature that remembers recently used attachments so files can be reattached without re-browsing folders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Betterbird has no purchase price and no subscription fee; the project is entirely funded by voluntary donations processed through Stripe, PayPal, and regional bank transfer options across North America, Europe, the UK, Canada, and Australia and New Zealand. Reports indicate fewer than 2 percent of Betterbird's users financially support the project, with donations split roughly evenly between North America and Europe, particularly Germany.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0905064-997b-4b5b-8fd6-50fee6bee0dd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
